import{_ as n,c as r,o,j as e,a as t}from"./js/framework-DqsPtFs4.js";const T=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"frontEnd/window/webRTC.md","filePath":"frontEnd/window/webRTC.md","lastUpdated":1733131829000}'),l={name:"frontEnd/window/webRTC.md"};function d(s,a,i,p,c,b){return o(),r("div",null,a[0]||(a[0]=[e("h2",{id:"webrtc-api",tabindex:"-1"},[t("WebRTC API "),e("a",{class:"header-anchor",href:"#webrtc-api","aria-label":'Permalink to "WebRTC API"'},"​")],-1),e("p",null,"WebRTC（Web 实时通信）是一种使 Web 应用程序和站点能够捕获和选择性地流式传输音频或视频媒体，以及在浏览器之间交换任意数据的而无需中间件的技术。WebRTC 的一系列标准使得在不需要用户安装插件或任何其他第三方软件的情况下，可以实现点对点数据共享和电话会议。",-1),e("p",null,"WebRTC 有多种用途；与媒体捕捉与媒体流 API 一起使用时，它们为 Web 提供了强大的多媒体功能，包括支持音频和视频会议、文件交换、屏幕共享、身份管理以及与传统电话系统的接口，包括发送 DTMF（按键拨号）信号。两个对等方之间的连接可以在不需要任何特殊驱动程序或插件的情况下建立，并且通常可以在没有任何中间服务器的情况下建立连接。",-1),e("p",null,"两个对等方之间的连接由 RTCPeerConnection 接口表示。一旦使用 RTCPeerConnection 建立并打开了连接，就可以向连接添加媒体流（MediaStream）或数据通道（RTCDataChannel）。",-1),e("p",null,"媒体流可以由任意数量的媒体信息轨道组成；轨道由基于 MediaStreamTrack 接口的对象表示，可以包含多种类型的媒体数据，包括音频、视频和文本（例如字幕甚至章节名称）。大多数流至少包含一个音频轨道和可能也包含一个视频轨道，并且可以用于发送和接收实时媒体或存储的媒体信息（例如流媒体电影）。",-1),e("p",null,"你还可以使用两个对等方之间的连接来交换任意二进制数据，使用 RTCDataChannel 接口。这可以用于反向信道信息、元数据交换、游戏状态数据包、文件传输，甚至作为数据传输的主要通道。",-1),e("p",null,[t("参考："),e("a",{href:"https://developer.mozilla.org/zh-CN/docs/Web/API/WebRTC_API",target:"_blank",rel:"noreferrer"},"https://developer.mozilla.org/zh-CN/docs/Web/API/WebRTC_API")],-1)]))}const R=n(l,[["render",d]]);export{T as __pageData,R as default};
